using UnityEngine;

public class Jewel : MonoBehaviour
{
    public enum JewelColor { Red, Blue, Green, Yellow }

    public JewelColor color;
    public bool isSelectable = true;
    public bool isSelected = false;

    private SpriteRenderer spriteRenderer;

    void Start()
    {
        spriteRenderer = GetComponent<SpriteRenderer>();
    }

    void Update()
    {
        if (isSelectable && Input.GetMouseButtonDown(0))
        {
            SelectJewel();
        }
    }

    void SelectJewel()
    {
        isSelected = true;
        spriteRenderer.color = new Color(spriteRenderer.color.r, spriteRenderer.color.g, spriteRenderer.color.b, 0.5f);
    }

    void DeselectJewel()
    {
        isSelected = false;
        spriteRenderer.color = new Color(spriteRenderer.color.r, spriteRenderer.color.g, spriteRenderer.color.b, 1f);
    }

    public JewelColor GetColor()
    {
        return color;
    }
}
```
Este script define una enum `JewelColor` para representar los colores de las gemas. La variable `color` almacenará el color de la gema. La variable `isSelectable` indica si la gema es seleccionable o no. La variable `isSelected` indica si la gema está seleccionada o no.

En el método `Start()`, se obtiene una referencia al `SpriteRenderer` del GameObject.

En el método `Update()`, se verifica si se ha presionado el botón izquierdo del mouse y si la gema es seleccionable. Si se cumple la condición, se llama al método `SelectJewel()`.

En el método `SelectJewel()`, se establece el valor de `isSelected` a `true` y se cambia el color de la gema a un color semi-transparente para indicar que ha sido seleccionada.

En el método `DeselectJewel()`, se establece el valor de `isSelected` a `false` y se restaura el color de la gema a su valor original.

Finalmente, el método `GetColor()` devuelve el color de la gema.

